// Re-implementing Maze Generation more robustly
function generateMaze(rows, cols, prng) {
    const grid = Array.from({ length: rows }, () => 
        Array.from({ length: cols }, () => ({ n: true, e: true, s: true, w: true }))
    );
    const visited = new Set();
    const stack = [[0, 0]];
    visited.add("0,0");

    while (stack.length > 0) {
        const [r, c] = stack[stack.length - 1];
        const neighbors = [];
        const dirs = [
            { dr: -1, dc: 0, name: 'n', opp: 's' },
            { dr: 1, dc: 0, name: 's', opp: 'n' },
            { dr: 0, dc: -1, name: 'w', opp: 'e' },
            { dr: 0, dc: 1, name: 'e', opp: 'w' }
        ];

        for (let d of dirs) {
            const nr = r + d.dr;
            const nc = c + d.dc;
            if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !visited.has(`${nr},${nc}`)) {
                neighbors.push({ dr: d.dr, dc: d.dc, name: d.name, opp: d.opp, nr, nc });
            }
        }

        if (neighbors.length > 0) {
            // Shuffle neighbors
            for (let i = neighbors.length - 1; i > 0; i--) {
                const j = Math.floor(prng.next() * (i + 1));
                [neighbors[i], neighbors[j]] = [neighbors[j], neighbors[i]];
            }
            const next = neighbors[0];
            grid[r][c][next.name] = false;
            grid[next.nr][next.nc][next.opp] = false;
            visited.add(`${next.nr},${next.nc}`);
            stack.push([next.nr, next.nc]);
        } else {
            stack.pop();
        }
    }
    return grid;
}

/**
 * Bot Logic
 */
class Bot {
    constructor(id, mazeGrid, rows, cols, exitR, exitC, preferredDirs, prng) {
        this.id = id;
        this.grid = mazeGrid;
        this.rows = rows;
        this.cols = cols;
        this.exitR = exitR;
        this.exitC = exitC;
        this.preferredDirs = preferredDirs; // Array of {dr, dc, name}
        this.path = [{ r: 0, c: 0 }];
        this.visited = new Set(["0,0"]);
        this.stack = [];
        this.deadEnds = [];
        this.finishTick = null;
        this.finished = false;

        // For smooth rendering
        this.visualX = 0;
        this.visualY = 0;
        this.cellSize = 400 / rows;
    }

    move(currentTick) {
        if (this.finished) return;

        const current = this.path[this.path.length - 1];
        let movedForward = false;

        for (let d of this.preferredDirs) {
            // Check if there is a wall in this direction
            if (!this.grid[current.r][current.c][d.name]) {
                const nr = current.r + d.dr;
                const nc = current.c + d.dc;
                const key = `${nr},${nc}`;

                if (!this.visited.has(key)) {
                    // Move to new cell
                    this.stack.push({ r: current.r, c: current.c });
                    this.path.push({ r: nr, c: nc });
                    this.visited.add(key);
                    movedForward = true;
                    break;
                }
            }
        }

        if (!movedForward) {
            // Backtrack
            if (this.stack.length > 0) {
                const prev = this.stack.pop();
                this.path.push(prev);
                // If we can't move forward from current, it's a dead end
                this.deadEnds.push({ r: current.r, c: current.c });
            } else {
                // Nowhere to go - should not happen in perfect maze unless exit found
            }
        }

        const newPos = this.path[this.path.length - 1];
        if (newPos.r === this.exitR && newPos.c === this.exitC) {
            this.finished = true;
            this.finishTick = currentTick;
        }
    }

    updateVisual(cellSize) {
        const target = this.path[this.path.length - 1];
        const tx = target.c * cellSize + cellSize / 2;
        const ty = target.r * cellSize + cellSize / 2;
        // Smooth interpolation (lerp)
        this.visualX += (tx - this.visualX) * 0.15;
        this.visualY += (ty - this.visualY) * 0.15;
    }
}

/**
 * Game Controller
 */
class Game {
    constructor() {
        this.canvas = document.getElementById('mazeCanvas');
        this.ctx = this.canvas.getContext('2d');
        this.rows = 20;
        this.cols = 20;
        this.spawn = { r: 0, c: 0 };
        this.exit = { r: 19, c: 19 };
        this.bots = [];
        this.grid = null;
        this.currentTick = 0;
        this.elapsed = 0;
        this.allBotsFinished = false;
        this.lastFinishTick = 0;
        this.cellSize = 400 / this.rows;

        this.reset(Date.now());
        this.animate();
    }

    reset(seed) {
        const prng = new PRNG(seed);
        this.grid = generateMaze(this.rows, this.cols, prng);
        this.currentTick = 0;
        this.elapsed = 0;
        this.allBotsFinished = false;
        this.lastFinishTick = 0;

        // Random exit
        this.exit = { 
            r: Math.floor(prng.next() * this.rows), 
            c: Math.floor(prng.next() * this.cols) 
        };
        if (this.exit.r === 0 && this.exit.c === 0) this.exit.r = 1;

        this.bots = [];
        const dirsBase = [
            { dr: -1, dc: 0, name: 'n' },
            { dr: 1, dc: 0, name: 's' },
            { dr: 0, dc: -1, name: 'w' },
            { dr: 0, dc: 1, name: 'e' }
        ];

        for (let i = 0; i < 24; i++) {
            // Each bot gets a unique shuffled direction order
            const prefs = JSON.parse(JSON.stringify(dirsBase));
            for (let j = prefs.length - 1; j > 0; j--) {
                const k = Math.floor(prng.next() * (j + 1));
                [prefs[j], prefs[k]] = [prefs[k], prefs[j]];
            }
            const bot = new Bot(i, this.grid, this.rows, this.cols, this.exit.r, this.exit.c, prefs, prng);
            // Initialize visual position to spawn
            bot.visualX = this.spawn.c * this.cellSize + this.cellSize / 2;
            bot.visualY = this.spawn.r * this.cellSize + this.cellSize / 2;
            this.bots.push(bot);
        }
    }

    tick(n) {
        for (let i = 0; i < n; i++) {
            if (this.allBotsFinished) break;
            this.currentTick++;

            let allDone = true;
            for (let bot of this.bots) {
                if (!bot.finished) {
                    bot.move(this.currentTick);
                    allDone = false;
                }
            }

            if (allDone) {
                this.allBotsFinished = true;
                this.lastFinishTick = this.currentTick;
            }
        }
        this.elapsed = this.allBotsFinished ? this.lastFinishTick : this.currentTick;
    }

    walls(r, c) {
        const cell = this.grid[r][c];
        return { n: cell.n, e: cell.e, s: cell.s, w: cell.w };
    }

    animate() {
        this.render();
        requestAnimationFrame(() => this.animate());
    }

    render() {
        const ctx = this.ctx;
        const cs = this.cellSize;
        ctx.clearRect(0, 0, 400, 400);

        // Draw Maze Walls
        ctx.strokeStyle = "#fff";
        ctx.lineWidth = 2;
        for (let r = 0; r < this.rows; r++) {
            for (let c = 0; c < this.cols; c++) {
                const cell = this.grid[r][c];
                const x = c * cs;
                const y = r * cs;
                ctx.beginPath();
                if (cell.n) { ctx.moveTo(x, y); ctx.lineTo(x + cs, y); }
                if (cell.e) { ctx.moveTo(x + cs, y); ctx.lineTo(x + cs, y + cs); }
                if (cell.s) { ctx.moveTo(x, y + cs); ctx.lineTo(x + cs, y + cs); }
                if (cell.w) { ctx.moveTo(x, y); ctx.lineTo(x, y + cs); }
                ctx.stroke();
            }
        }

        // Draw Exit
        ctx.fillStyle = "rgba(0, 255, 0, 0.3)";
        ctx.fillRect(this.exit.c * cs, this.exit.r * cs, cs, cs);
        ctx.strokeStyle = "#0f0";
        ctx.strokeRect(this.exit.c * cs + 4, this.exit.r * cs + 4, cs - 8, cs - 8);

        // Draw Bots
        const colors = ["#ff0000", "#00ff00", "#0000ff", "#ffff00", "#ff00ff", "#00ffff", "#ffa500", "#a52a2a"];
        for (let i = 0; i < this.bots.length; i++) {
            const bot = this.bots[i];
            bot.updateVisual(cs);
            ctx.fillStyle = colors[i % colors.length];
            ctx.beginPath();
            ctx.arc(bot.visualX, bot.visualY, cs * 0.25, 0, Math.PI * 2);
            ctx.fill();
        }

        // Update UI
        const completedCount = this.bots.filter(b => b.finished).length;
        document.getElementById('completed').innerText = completedCount;
        document.getElementById('timer').innerText = this.elapsed;
    }
}

// Initialize Game and API
const gameInstance = new Game();
window.game = {
    tick: (n) => gameInstance.tick(n),
    reset: (seed) => gameInstance.reset(seed || Date.now()),
    get elapsed() { return gameInstance.elapsed; },
    get size() { return { rows: gameInstance.rows, cols: gameInstance.cols }; },
    get spawn() { return gameInstance.spawn; },
    get exit() { return gameInstance.exit; },
    walls: (r, c) => gameInstance.walls(r, c),
    get bots() { return gameInstance.bots; }
};

// UI Binding
document.getElementById('reset').addEventListener('click', () => {
    window.game.reset();
});

</script>
